# setup_supabase_auth.ps1 - Integracion Supabase Auth
Write-Host "Instalando autenticacion Supabase..." -ForegroundColor Cyan

$dir = Split-Path ".env.local" -Parent
if ($dir) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\.env.local", $text, [System.Text.Encoding]::UTF8)
Write-Host "  OK: .env.local" -ForegroundColor Yellow

$dir = Split-Path "src\lib\supabase.ts" -Parent
if ($dir) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\lib\supabase.ts", $text, [System.Text.Encoding]::UTF8)
Write-Host "  OK: src/lib/supabase.ts" -ForegroundColor Yellow

$dir = Split-Path "src\store\erp.auth.store.ts" -Parent
if ($dir) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\store\erp.auth.store.ts", $text, [System.Text.Encoding]::UTF8)
Write-Host "  OK: src/store/erp.auth.store.ts" -ForegroundColor Yellow

$dir = Split-Path "supabase_setup.sql" -Parent
if ($dir) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\supabase_setup.sql", $text, [System.Text.Encoding]::UTF8)
Write-Host "  OK: supabase_setup.sql" -ForegroundColor Yellow

Write-Host ""
Write-Host "Supabase Auth instalado!" -ForegroundColor Green
Write-Host "Ahora ejecuta el SQL en Supabase Dashboard" -ForegroundColor Cyan
